def main():
    conn = sqlite3.connect(DB_PATH)
    cursor = conn.cursor()

    cursor.execute('DELETE FROM spr_shensha_config')
    cursor.executemany('''
        INSERT INTO spr_shensha_config
        (star_key, display_name_ru, display_name_zh, category, nature, color_hex, is_active, tooltip_text, interpretation_text, short_interpretation, source, display_order)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    ''', stars)

    conn.commit()
    print(f'Inserted {len(stars)} stars into spr_shensha_config')
    conn.close()


if __name__ == '__main__':
    main()
